DELETE FROM vehicle360.control.pipeline_dependency WHERE parent_pipeline_id LIKE 'PL_SILVER_%' OR parent_pipeline_id LIKE 'PL_GOLD_%' OR child_pipeline_id LIKE 'PL_SILVER_%' OR child_pipeline_id LIKE 'PL_GOLD_%';
