DELETE FROM vehicle360.control.pipeline_watermark WHERE pipeline_id LIKE 'PL_SILVER_%' OR pipeline_id LIKE 'PL_GOLD_%';
DELETE FROM vehicle360.control.pipeline_config WHERE pipeline_id LIKE 'PL_SILVER_%' OR pipeline_id LIKE 'PL_GOLD_%';

